export interface HarmonyIAMRole {
    roleArn: string;
    resourceId: string;
    displayName: string;
    description: string;
    approvedAppNames: string[];
    lastUpdatedBy: string;
    lastUpdatedOn: number;
    allowAllApps?: boolean;
    isEnforced?: boolean;
    expiration?: number;
}
export interface HarmonyApiIAMRoles {
    /**
     * Creates Harmony IAM Role resource in order to restrict users and apps that can assume a certain role.
     *
     * @param {String} roleArn (required) roleArn to create the Harmony IAM Role resource for.
     * @param {String} parentBindleId (required) Parent Bindle ID that will be the owner of this resource.
     * @param {String} displayName (required) Display name of the IAM Role.
     * @param {String} description (required) Description of of the IAM Role.
     * @param {String[]} approvedAppNames (required) Name of the apps allowed to assume this role from.
     * @param {boolean} allowAllApps if true, it will all Apps to assume the role and ignore the approvedAppNames field.
     * @param {boolean} isEnforced if true, it will do permission check for calling this IAM Role.
     * @memberof window.harmony.api.iamRoles
     * @async
     */
    create: ({ roleArn, parentBindleId, displayName, description, approvedAppNames, allowAllApps, isEnforced }: {
        roleArn: string;
        parentBindleId: string;
        displayName: string;
        description: string;
        approvedAppNames: string[];
        allowAllApps?: boolean;
        isEnforced?: boolean;
    }) => Promise<HarmonyIAMRole>;
    /**
     * Updates the Harmony IAM Role but permissions can only be managed through Bindles UI.
     * Must have the 'Can manage' permmission to be able to update.
     *
     * @param {String} roleArn (required) roleArn to update.
     * @param {String} displayName (required) Display name of the IAM Role.
     * @param {String} description (required) Description of of the IAM Role.
     * @param {String[]} approvedAppNames (required) Name of the apps allowed to assume this role from.
     * @param {boolean} allowAllApps if true, it will all Apps to assume the role and ignore the approvedAppNames field.
     * @param {boolean} isEnforced if true, it will do permission check for calling this IAM Role.
     * @memberof window.harmony.api.iamRoles
     * @async
     */
    update: ({ roleArn, displayName, description, approvedAppNames, allowAllApps, isEnforced }: {
        roleArn: string;
        displayName: string;
        description: string;
        approvedAppNames: string[];
        allowAllApps?: boolean;
        isEnforced?: boolean;
    }) => Promise<HarmonyIAMRole>;
    /**
     * Deletes the Harmony IAM Role.
     * Must have the 'Can manage' permmission to be able to delete.
     *
     * @param {String} roleArn (required) roleArn to create the Harmony IAM Role resource for.
     * @memberof window.harmony.api.iamRoles
     * @async
     */
    delete: ({ roleArn }: {
        roleArn: string;
    }) => Promise<HarmonyIAMRole>;
    /**
     * Fetches the specific Harmony IAM Resource based on the roleArn
     *
     * @param {String} roleArn (required) roleArn to create the Harmony IAM Role resource for.
     * @memberof window.harmony.api.iamRoles
     * @async
     */
    get: ({ roleArn }: {
        roleArn: string;
    }) => Promise<HarmonyIAMRole>;
    /**
     * Fetches a list of all Harmony IAM Resources.
     *
     * @memberof window.harmony.api.iamRoles
     * @async
     */
    list: () => Promise<HarmonyIAMRole[]>;
    /**
     * Fetches a list of all Harmony IAM Resources that the user has permission to.
     *
     * @param {String} permission (required) permission to check for the authorized iamRoles. "Can manage" or "Can assume"
     * @memberof window.harmony.api.iamRoles
     * @async
     */
    listAuthorized: ({ permission }: {
        permission: string;
    }) => Promise<HarmonyIAMRole[]>;
}
